import asyncio
from aiocoap import *

class CoAPServer(Resource):
    def __init__(self):
        super().__init__()
        self.temperature = 0
        self.light = False

    async def render_get(self, request):
        if 'temp' in request.uri_path:
            payload = str(self.temperature).encode('utf-8')
            return Message(code=CHANGED, payload=payload)
        
        elif 'light' in request.uri_path:
            payload = str(self.light).encode('utf-8')
            return Message(code=CHANGED, payload=payload)
        
    async def render_put(self, request):
        if 'temp' in request.uri_path:
            self.temperature = int(request.payload)
        
        elif 'light' in request.uri_path:
            self.light = bool(int(request.payload))  # assuming payload is an integer (1 or 0)

        return Message(code=CHANGED, payload=b"Changed")

